function safeStr(value){ return marionSafeCleanText(value); }

function normalizeEchoTextForCompare(value=""){return safeStr(value).toLowerCase().replace(/[“”]/g,'"').replace(/[‘’]/g,"'").replace(/[^a-z0-9]+/g," ").replace(/\s+/g," ").trim();}
function isPromptEchoReply(reply="",prompt=""){const r=normalizeEchoTextForCompare(reply),p=normalizeEchoTextForCompare(prompt);if(!r||!p)return false;return r===p||p.includes(r)&&r.length>12||r.includes(p)&&p.length>12;}
function isExcessExpressionReply(value=""){return /\b(stop the echo|switching from invitation to execution|recovery line has already served its purpose|next line must carry progress|public knowledge topic|useful answer should|six-domain layer|final envelope|state spine|progression shaping|runtimeTelemetry|replyAuthority|diagnostic packet)\b/i.test(safeStr(value));}
function buildNyxMarionContinuityComposerReply(prompt=""){
  const t=safeStr(prompt).toLowerCase().replace(/[.!?]+$/g,"").trim();
  if(!t)return"";
  if(/\bwhat\s+is\s+marion\s+supposed\s+to\s+do\b|\bwhat\s+does\s+marion\s+do\b|\bmarion\s+role\b/.test(t))return"Marion is the deeper coordination layer behind Nyx. Nyx stays public-facing and conversational while Marion helps preserve intent, context, routing, and clean response handoff in the background.";
  if(/\bcan\s+(?:marion|you)\s+carry\s+context\s+across\s+turns\b|\bcarry\s+context\s+across\s+turns\b/.test(t))return"Yes. The goal is for Nyx to keep the conversation natural while Marion carries the useful context behind the scenes, so follow-up questions stay connected instead of restarting the conversation.";
  if(/\bwhy\s+is\s+that\s+important\s+for\s+nyx\b|\bwhy\s+does\s+that\s+matter\s+for\s+nyx\b/.test(t))return"It matters because Nyx is the public voice. If Marion carries the thread behind the scenes, Nyx can answer follow-up questions naturally without making the user restate the topic every turn.";
  if(/\bhow\s+does\b.{0,160}\bhelp\s+sandblast\b|\bhelp\s+sandblast\b/.test(t))return"It helps Sandblast because Nyx becomes easier to talk to and Marion keeps the useful context in the background. That means users can ask follow-up questions naturally, stay engaged longer, and move through radio, TV, news, and business prompts without the interface feeling like it resets every turn.";
  if(/^(?:next\s+steps?|what(?:'|’)?s\s+next|what\s+next|then\s+what)$/.test(t))return"Next steps: keep the public Nyx route clean, run the five-turn continuity test, confirm each follow-up advances the thread, then lock the stable handoff before adding new features.";
  return"";
}


function shouldOverrideComposerContinuityReply(prompt="",reply="",candidate=""){
  const p=safeStr(prompt).toLowerCase();
  const r=safeStr(reply).toLowerCase();
  const c=safeStr(candidate);
  if(!p||!c)return false;
  if(!r)return true;
  if(normalizeEchoTextForCompare(r)===normalizeEchoTextForCompare(c))return false;
  if(/\bsandblast\b/i.test(p)&&/\bhelp|business|users?|engaged|radio|tv|news\b/i.test(p)&&!/\bsandblast\b/i.test(r))return true;
  if(/\bwhy\b/i.test(p)&&/\bnyx\b/i.test(p)&&!/\bnyx\b/i.test(r))return true;
  if(/\bnext\s+steps?\b/i.test(p)&&!/\bnext\s+steps?|test|confirm|lock|handoff\b/i.test(r))return true;
  return false;
}

function deterministicComposerKnowledgeReply(prompt=""){const t=safeStr(prompt).toLowerCase();
  const handoffReply=buildNyxMarionContinuityComposerReply(prompt);
  if(handoffReply)return handoffReply;
  if(/\bconsideration\b.*\bcontract\s+law\b|\bcontract\s+law\b.*\bconsideration\b/.test(t))return 'In contract law, consideration is the value exchanged between parties, such as money, services, a promise, or a benefit. It helps show that an agreement is more than a one-sided gift. This is general legal information, not legal advice.';
  if(/\bpromise\b.*\bconsideration\b|\bconsideration\b.*\bpromise\b/.test(t))return 'A promise can be consideration when it is bargained for as part of an exchange. A bare promise with no exchange is usually not enough, but mutual promises can support a contract. The exact rule depends on jurisdiction.';
  if(/\bcommon\s+exceptions\b|\bexceptions\b.*\bconsideration\b/.test(t))return 'Common consideration-related exceptions or doctrines include promissory estoppel, deeds or sealed instruments in some systems, statutory modifications, and some part-payment rules. The details depend on jurisdiction.';
  if(/\bbreak a leg\b/.test(t))return /instead of good luck|why would/i.test(t)?'Someone says “break a leg” instead of “good luck” because theatre culture treats direct good-luck wishes as unlucky. The phrase became a ritualized, indirect way to encourage someone before a performance.':'Literally, “break a leg” means to injure a leg. Culturally, it is an English idiom used to wish someone good luck, especially before a performance. It is not meant as harm; it is a superstition-based way of saying, “I hope you do well.”';
  if(/\bspill the beans\b/.test(t))return '“Spill the beans” means to reveal information that was meant to stay secret. Literally it suggests dropping beans; idiomatically, it means exposing a secret or surprise too early.';
  if(/\bbless your heart\b/.test(t))return '“Bless your heart” can be sincere or cutting depending on tone and setting. In the American South, it can mean genuine sympathy, but it can also soften criticism, pity, or disapproval. The cultural meaning depends on relationship, delivery, and context.';
  if(/\bi[’']?m fine\b/.test(t))return '“I’m fine” can be literal, but behaviourally it can also signal masking, avoidance, or a desire to end the topic. Marion should not assume distress automatically; the safer read is to examine tone, timing, context, and whether the phrase conflicts with visible behaviour.';
  if(/\b(?:defensive\s+escalation|intent\s+justifier|god[-\s]?ray|audio\s+alert|alarm\s+feature|90\s*dB|decibel|aster|talon)\b/.test(t)&&/\b(?:ethic|guardrail|protect|defen[cs]e|safety|boundary|justif|alarm|alert|scenario)\b/.test(t))return 'For Marion, Aster, or Talon, elevated defensive signalling should stay advisory and bounded: explicit verified command, protective purpose, permission boundary, immediate-threat justification for any elevated output, short capped bursts, cooldown intervals, audit logging, and no punitive, coercive, continuous, or identity-targeted use. Marion keeps final authority; the gatekeeper only supplies the ethical metadata.';
  if(/\bdomain\s+routing\b|\bdomain\s+router\b|\broute\s+domains?\b/.test(t))return 'Domain routing is Marion’s triage layer. It reads the user’s intent, selects the best knowledge lane, such as technical, psychology, English, AI, cyber, law, or finance, and sends the turn there so Marion can answer from the right context instead of guessing. In this system, the router should preserve the user’s original question, prevent cross-domain bleed, and hand one clean final reply back to the interface.';
  if(/\breference\s*error\b|\breferenceerror\b|\bis not defined\b|\bcannot access .* before initialization\b/.test(t))return 'A ReferenceError means a script tried to use a variable, function, or module binding that was not available in that runtime scope. The fix is to identify the missing symbol, correct the import/export or declaration order, and return a safe final reply instead of letting the raw diagnostic become Marion’s visible answer.';
  if(/\binstead of good luck\b/.test(t)||/\bwhy would someone say that\b/.test(t))return 'They would say it as an indirect good-luck wish, usually referring to “break a leg.” In theatre culture, saying “good luck” directly is considered unlucky, so the indirect phrase became the accepted ritual.';
  return '';}



