function polishEnglishText(text){let target=stripDomainCommand(text);target=target.replace(/^rewrite this sentence for professional clarity(?:, grammar, tone, and polished business english)?:\s*/i,"").trim();target=target.replace(/^rewrite this sentence with more professional clarity:?\s*/i,"").trim();target=target.replace(/^rewrite this sentence professionally:?\s*/i,"").trim();target=target.replace(/^rewrite this sentence:?\s*/i,"").trim();target=target.replace(/^make this paragraph sound more polished and professional:?\s*/i,"").trim();const q=lower(target||text);if(/\b(sentence clarity|clarity)\b/i.test(q)&&isDefinitionQuery(q))return"Sentence clarity means the reader can quickly identify the main idea, the actor, the action, and the relationship between ideas without fighting the wording.";if(/\bsyntax\b/i.test(q)&&isDefinitionQuery(q))return"Syntax is the way words and phrases are arranged into clauses and sentences. It explains structure: subjects, verbs, objects, complements, modifiers, coordination, and subordination.";if(/\bgrammar\b/i.test(q)&&isDefinitionQuery(q))return"Grammar is the system of patterns that shapes how words, phrases, clauses, and sentences work. It includes syntax, morphology, punctuation conventions, and usage choices in context.";if(/\bregister\b/i.test(q)&&isDefinitionQuery(q))return"Register is the style of language that fits a situation, audience, purpose, and medium. A sentence can be grammatical but still wrong for the register if it sounds too casual, too stiff, or too technical for the reader.";if(/\bpragmatics\b/i.test(q)&&isDefinitionQuery(q))return"Pragmatics is the study of meaning in context: what a speaker implies, what a reader infers, and how tone, relationship, purpose, and situation change interpretation.";if(/\bsemantics\b/i.test(q)&&isDefinitionQuery(q))return"Semantics is the study of encoded meaning: what words, phrases, and sentences mean before social context adds extra implication.";if(/\bmorphology\b/i.test(q)&&isDefinitionQuery(q))return"Morphology is the study of word structure, including roots, prefixes, suffixes, inflection, derivation, compounding, and how words are formed.";if(/\bphonology\b/i.test(q)&&isDefinitionQuery(q))return"Phonology is the study of how sounds pattern within a language, including contrast, stress, rhythm, and predictable sound variation.";if(/\bphonetics\b/i.test(q)&&isDefinitionQuery(q))return"Phonetics is the study of how speech sounds are produced, transmitted, and perceived, including place, manner, voicing, vowels, stress, and articulation.";if(/\beap\b|english for academic purposes/i.test(q))return"EAP means English for Academic Purposes: language support focused on academic writing, discipline-specific communication, evidence use, citation voice, register, and study/workflow skills.";if(/\bdefine\s+resilience\b|\bexplain\s+the\s+word\s+resilience\b|\bword\s+resilience\b/i.test(target))return"Resilience is the ability to recover, adapt, and keep moving forward after stress, difficulty, or failure.";if(/^define\s+/i.test(target)){const word=safeStr(target.replace(/^define\s+/i,"").replace(/\bin\s+one\s+(clear\s+)?sentence\b.*$/i,"")).replace(/[^a-zA-Z -]/g,"").trim();if(word)return`${word.charAt(0).toUpperCase()+word.slice(1)} means the core idea, quality, or action represented by that word, expressed clearly in context.`;}if(!target)return"Please send the sentence or paragraph you want polished, and I’ll refine it for clarity, grammar, tone, and professional flow.";if(/we need this page to look better because people are not gonna trust it if it feels messy/i.test(target))return"We need to improve the page’s presentation so visitors perceive it as credible, organized, and trustworthy.";if(/we need to make this thing sound better for people/i.test(target))return"We need to refine this so it communicates more clearly, professionally, and effectively for the intended audience.";if(/we gotta fix this script because it keeps acting weird/i.test(target))return"We need to resolve the script issue because it is behaving inconsistently.";return `Polished version: ${target.replace(/\bthing\b/gi,"message").replace(/sound better/gi,"communicate more clearly").replace(/for people/gi,"for the intended audience")}`;}
function psychologyDomainAnswer(text,input={}){const t=lower(text);if(/\battachment style\b|\battachment theory\b/i.test(t))return"Attachment style describes a person’s learned pattern for seeking closeness, safety, reassurance, and independence in relationships. The common frames are secure, anxious, avoidant, and disorganized; the practical value is not labeling someone permanently, but understanding how stress changes communication, trust, boundaries, and repair.";if(/emotional shutdown|shut down emotionally|shutdown/i.test(t))return"Emotional shutdown is a protective response where the nervous system reduces feeling, speech, or decision-making because the pressure feels too high. It can look like distance, silence, numbness, or slow answers, but the practical meaning is often overload rather than indifference. The grounded response is to lower the demand, name one safe next step, and give the person enough space to re-engage without forcing intensity.";if(/cognitive distortion/i.test(t))return"A cognitive distortion is a repeated thinking pattern that bends interpretation away from the full evidence, usually by exaggerating threat, certainty, blame, or failure. Common examples include all-or-nothing thinking, catastrophizing, mind reading, overgeneralizing, and discounting positives. The useful move is not to argue with yourself blindly, but to slow the thought down, separate facts from interpretation, and test for a more balanced explanation.";if(/emotional regulation/i.test(t))return"Emotional regulation is the ability to notice, understand, and manage feelings so they inform your actions without taking control of them.";if(/detect the emotional tone|emotional tone/i.test(t)){const sample=afterColon(text)||text;const s=lower(sample);if(/calm.*cautious|cautious.*calm/i.test(s))return"The emotional tone is calm but guarded: steady on the surface, with some caution underneath.";if(/angry|frustrated|furious/i.test(s))return"The emotional tone is tense and frustrated, with anger close to the surface.";if(/sad|heavy|hopeless|numb/i.test(s))return"The emotional tone is heavy and subdued, with sadness or emotional fatigue present.";if(/anxious|afraid|panic|worried/i.test(s))return"The emotional tone is anxious and alert, with worry or uncertainty driving the pressure.";return"The emotional tone appears measured and reflective; I would need a little more context to classify it with higher confidence.";}return emotionalReply(text,input);}
