function identityReply(text,input={}){const t=lower(text);if(/what is marion|who is marion|marion helps|how marion|what marion does|marion does for nyx|how do you think|marion.*think|think/i.test(t))return "Marion is the deeper reasoning layer behind me. I handle the conversation you see and hear, while Marion helps with intent, context, memory, and response shaping in the background. The goal is simple: you speak to Nyx, and the system gives you a clear, useful answer without exposing the machinery unless you ask for it.";return "I’m Nyx — the live interface for Sandblast. Marion is the deeper cognitive system behind me, helping interpret intent, preserve context, and shape responses so this feels like one coordinated intelligence instead of a loose chatbot.";}

function extractBroadAnswerableConceptTerm(text=""){
  const raw=safeStr(text).replace(/[?!.]+$/g,"").trim();
  if(!raw)return "";
  const patterns=[
    /^(?:please\s+)?(?:can you\s+|could you\s+|would you\s+)?tell me\s+(?:something\s+)?about\s+(.+)$/i,
    /^(?:please\s+)?(?:explain|describe|define|break down)\s+(.+)$/i,
    /^(?:please\s+)?what\s+(?:is|are)\s+(.+)$/i,
    /^(?:please\s+)?what\s+does\s+(.+?)\s+mean$/i,
    /^(?:please\s+)?give me\s+(?:an overview|a quick overview|information|some info)\s+(?:about|on|regarding)\s+(.+)$/i
  ];
  for(const rx of patterns){
    const m=raw.match(rx);
    if(m&&m[1]){
      const term=safeStr(m[1]).replace(/\b(in|for|within)\s+(business|ai|psychology|law|finance|cyber|english)\s*$/i,"").trim();
      if(term&&term.length>=2&&term.length<=120)return term;
    }
  }
  return "";
}
function isBroadAnswerableConceptPrompt(text="",input={},routed={}){
  const term=extractBroadAnswerableConceptTerm(text);
  if(!term)return false;
  if(isNyxMarionBackendTechnicalContext(text)||detectDirectiveIntent(text)||isCapabilityQuestion(text))return false;
  if(/\b(which|where exactly|what specific|choose|pick one|interface|radio|media|roku|backend technical work)\b/i.test(lower(text)))return false;
  return true;
}
function broadConceptFallbackReply(text="",input={},routed={}){
  const term=extractBroadAnswerableConceptTerm(text);
  if(!term)return "";
  const key=lower(term);
  if(/\baudit(ing)?\b/.test(key))return "Auditing is a structured review process that checks whether records, systems, finances, operations, or decisions are accurate, compliant, and trustworthy. In business, it protects the organization by finding gaps, confirming evidence, reducing risk, and showing where controls or processes need to be tightened.";
  if(/\bdigital transformation\b/.test(key))return "Digital transformation means redesigning how a business operates by using technology to improve workflows, customer experience, data visibility, and speed of execution. The important part is not just adding software; it is changing the operating model so the company becomes more adaptive, measurable, and scalable.";
  if(/\bcognitive intelligence\b/.test(key))return "Cognitive intelligence is the ability to learn, reason, interpret patterns, solve problems, and adapt decisions based on context. In an AI or business system, it shows up as better understanding, cleaner judgment, stronger prioritization, and the ability to move beyond scripted responses.";
  if(/\borganizational intelligence\b/.test(key))return "Organizational intelligence is a company’s ability to collect signals, learn from them, coordinate decisions, and act effectively. A business with strong organizational intelligence does not just store information; it turns that information into timing, strategy, and operational advantage.";
  if(/\bbusiness strategy\b/.test(key))return "Business strategy is the practical logic behind how a company wins: who it serves, what value it delivers, how it differentiates, how it earns revenue, and where it focuses resources. A strong strategy makes tradeoffs clear instead of trying to chase every opportunity.";
  const label=term.charAt(0).toUpperCase()+term.slice(1);
  return `${label} is best understood as a practical concept with a definition, a purpose, and an execution angle. At the simplest level, it describes how a person or organization interprets a situation, makes choices, and turns those choices into action. The useful way to approach it is to ask what it means, why it matters, where it applies, and what decision it should improve.`;
}

